import outlines
from outlines.prompts import register_filter, unregister_filter

register_filter('shout', lambda s: s.upper())

@outlines.prompt
def p1(text):
    '''{{ text | shout }}'''
print(p1('hi'))

@outlines.prompt(filters={'shout': lambda s: s.lower()})
def p2(text):
    '''{{ text | shout }}'''
print(p2('HI'))

